// Build URL list from annotation_base.json
// URLs are hardcoded here — update when annotation_base.json changes
// To add a new supplier: add entries to the URLS array below

const URLS = [
  // HERTZ_ES
  { record:'HERTZ_ES', supplier:'Hertz', country:'ES', path:'sources.primary',        url:'https://images.hertz.com/pdfs/RT_FULL_ES_EN.pdf', fields:[] },
  { record:'HERTZ_ES', supplier:'Hertz', country:'ES', path:'sources.secondary[0]',   url:'https://images.hertz.com/pdfs/RT_FULL_ES_ES.pdf', fields:[] },
  { record:'HERTZ_ES', supplier:'Hertz', country:'ES', path:'sources.secondary[1]',   url:'https://www.hertz.es/rentacar/customersupport/index.jsp?targetPage=faq.jsp', fields:['grace_period_minutes','licence_rules'] },
  { record:'HERTZ_ES', supplier:'Hertz', country:'ES', path:'sources.secondary[2]',   url:'https://hertz.my.site.com/care/articles/es/FAQ/Tarjetas-de-d%C3%A9bito-prepago-1491399187323?r=69&ui-knowledge-components-aura-actions.KnowledgeArticleVersionCreateDraftFromOnlineAction.createDraftFromOnlineArticle=1', fields:['payment_rules'] },
  // HERTZ_DE
  { record:'HERTZ_DE', supplier:'Hertz', country:'DE', path:'sources.primary',        url:'https://images.hertz.com/pdfs/RT_FULL_DE_EN.pdf', fields:[] },
  { record:'HERTZ_DE', supplier:'Hertz', country:'DE', path:'sources.secondary[0]',   url:'https://www.hertz.de/p/fahrzeug-guide/buchen-sie-ihren-mietwagen', fields:['licence_rules'] },
  { record:'HERTZ_DE', supplier:'Hertz', country:'DE', path:'sources.secondary[1]',   url:'https://hertz.my.site.com/care/articles/en_GB/FAQ/Debit-Cards-1491399193040', fields:['payment_rules'] },
  // SIXT_ES
  { record:'SIXT_ES',  supplier:'Sixt',  country:'ES', path:'sources.primary',        url:'https://www.sixt.es/php/terms/view?language=en_US&liso=ES&rtar=000&view=EPP&tlang=es_ES&style=typo3', fields:[] },
  { record:'SIXT_ES',  supplier:'Sixt',  country:'ES', path:'sources.secondary[0]',   url:'https://www.sixt.es/help-center/sections/como-llegar-y-llegada/', fields:['grace_period_minutes'] },
  { record:'SIXT_ES',  supplier:'Sixt',  country:'ES', path:'sources.secondary[1]',   url:'https://www.sixt.es/shared/t-c/sixt_ES_en.pdf', fields:['payment_rules','cross_border_conditions'] },
  { record:'SIXT_ES',  supplier:'Sixt',  country:'ES', path:'sources.secondary[2]',   url:'https://www.sixt.es/help-center/articles/necesito-un-permiso-de-conducir-internacional-para-alquilar-con-sixt/', fields:['licence_rules'] },
  // SIXT_DE
  { record:'SIXT_DE',  supplier:'Sixt',  country:'DE', path:'sources.primary',        url:'https://www.sixt.de/php/terms/view?language=en_US&liso=DE&rtar=000&view=EPP&tlang=de_DE&style=typo3', fields:[] },
  { record:'SIXT_DE',  supplier:'Sixt',  country:'DE', path:'sources.secondary[0]',   url:'https://www.sixt.de/help-center/sections/anfahrt-und-ankunft/', fields:['grace_period_minutes'] },
  { record:'SIXT_DE',  supplier:'Sixt',  country:'DE', path:'sources.secondary[1]',   url:'https://www.sixt.de/help-center/articles/welchen-fuehrerschein-brauche-ich-fuer-eine-anmietung-bei-sixt-in-deutschland/', fields:['licence_rules'] },
  { record:'SIXT_DE',  supplier:'Sixt',  country:'DE', path:'sources.secondary[2]',   url:'https://www.sixt.de/pages/mietinformationen/', fields:['payment_rules'] },
  // GOLDCAR_ES
  { record:'GOLDCAR_ES', supplier:'Goldcar', country:'ES', path:'sources.primary',      url:'https://www.goldcar.es/en-gb/terms-and-conditions/', fields:[] },
  { record:'GOLDCAR_ES', supplier:'Goldcar', country:'ES', path:'sources.secondary[0]', url:'https://www.goldcarhelp.com/faqs/319-puedo-recoger-el-vehiculo-fuera-del-horario-de-apertura-de-la-oficina', fields:['grace_period_minutes'] },
  { record:'GOLDCAR_ES', supplier:'Goldcar', country:'ES', path:'sources.secondary[1]', url:'https://www.goldcarhelp.com/faqs/227-que-permisos-de-conducir-aceptamos', fields:['licence_rules'] },
  { record:'GOLDCAR_ES', supplier:'Goldcar', country:'ES', path:'sources.secondary[2]', url:'https://www.goldcarhelp.com/faqs/320-metodos-de-pago', fields:['payment_rules'] },
  { record:'GOLDCAR_ES', supplier:'Goldcar', country:'ES', path:'sources.secondary[3]', url:'https://gcdata-documents.s3.amazonaws.com/APPENDIX%20-%20EN%20-%20Insurance%20and%20additional%20covers%20-%20Feb%202026%20%281%29.docx.pdf', fields:['tpl_amount'] },
];

// Return each URL as a separate item for the HTTP Request node
return URLS.map(u => ({ json: { ...u, runTimestamp: new Date().toISOString() } }));

// Classify the HTTP response into a status
const JS_RENDER_THRESHOLD = 5000;

const meta  = $input.item.json;          // url metadata from Build URL List
const resp  = meta.statusCode !== undefined ? meta : {};

// n8n HTTP Request with fullResponse=true puts status in statusCode
const statusCode  = meta.statusCode || 0;
const headers     = meta.headers     || {};
const body        = typeof meta.body === 'string' ? meta.body : JSON.stringify(meta.body || '');
const contentType = headers['content-type'] || headers['Content-Type'] || '';
const location    = headers['location']     || headers['Location']     || '';

let status, note, redirectUrl = null;

if (statusCode === 0) {
  status = 'TIMEOUT';
  note   = 'No response — connection failed or timed out';
} else if (statusCode === 404) {
  status = 'NOT_FOUND';
  note   = 'HTTP 404 — URL no longer exists';
} else if (statusCode === 403) {
  status = 'BLOCKED';
  note   = 'HTTP 403 — server blocks bots, URL likely valid';
} else if (statusCode >= 300 && statusCode < 400 && location) {
  status      = 'REDIRECT';
  redirectUrl = location;
  note        = `Redirected to: ${location}`;
} else if (statusCode >= 400) {
  status = 'ERROR';
  note   = `HTTP ${statusCode}`;
} else if (contentType.includes('text/html')) {
  const textOnly = body.replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
  if (textOnly.length < JS_RENDER_THRESHOLD) {
    status = 'JS_RENDERED';
    note   = `Only ${textOnly.length} chars extracted — likely JS-rendered`;
  } else {
    status = 'OK';
    note   = `${body.length.toLocaleString()} bytes | ${contentType.split(';')[0].trim()}`;
  }
} else {
  status = 'OK';
  note   = `${body.length.toLocaleString()} bytes | ${contentType.split(';')[0].trim()}`;
}

const ACTION_STATUSES = new Set(['NOT_FOUND','JS_RENDERED','REDIRECT','TIMEOUT','ERROR']);

return {
  json: {
    record:        meta.record,
    supplier:      meta.supplier,
    country:       meta.country,
    path:          meta.path,
    url:           meta.url,
    fieldsCovered: meta.fields || [],
    runTimestamp:  meta.runTimestamp,
    status,
    statusCode,
    note,
    redirectUrl,
    isIssue: ACTION_STATUSES.has(status),
  }
};

// Aggregate all URL check results
const items      = $input.all();
const allResults = items.map(i => i.json);
const issues     = allResults.filter(r => r.isIssue);

const runTimestamp = allResults[0]?.runTimestamp || new Date().toISOString();
const runDate      = runTimestamp.split('T')[0];

const totalChecked = allResults.filter(r => r.status !== 'SKIP').length;
const totalOk      = allResults.filter(r => r.status === 'OK').length;
const totalBlocked = allResults.filter(r => r.status === 'BLOCKED').length;
const totalSkipped = allResults.filter(r => r.status === 'SKIP').length;

console.log(`[TermsIQ URL Agent] ${runDate} — Checked: ${totalChecked} | OK: ${totalOk} | Issues: ${issues.length}`);

return [{ json: {
  runTimestamp, runDate,
  totalChecked, totalOk, totalBlocked, totalSkipped,
  issuesCount: issues.length,
  issues,
  allResults,
  exitCode: issues.length > 0 ? 1 : 0,
}}];

const data   = $input.first().json;
const issues = data.issues || [];

const statusColors = { 'NOT_FOUND':'#dc2626','JS_RENDERED':'#d97706','REDIRECT':'#2563eb','TIMEOUT':'#7c3aed','ERROR':'#dc2626' };
const actionGuide  = {
  'NOT_FOUND':   'URL deleted. Find replacement and update annotation_base.json + Build URL List node.',
  'JS_RENDERED': 'Page now JS-rendered. Add or update PDF fallback URL.',
  'REDIRECT':    'URL moved. Update annotation_base.json and Build URL List node with new URL.',
  'TIMEOUT':     'Server slow. Retry manually before taking action.',
  'ERROR':       'Unexpected error. Check URL manually.',
};

let rows = '';
for (const issue of issues) {
  const color  = statusColors[issue.status] || '#374151';
  const action = actionGuide[issue.status]  || 'Check manually.';
  const fields = issue.fieldsCovered?.length ? `<br><small style="color:#6b7280">Fields: ${issue.fieldsCovered.join(', ')}</small>` : '';
  rows += `<tr>
    <td style="padding:8px;border:1px solid #e5e7eb;font-weight:bold">${issue.record}</td>
    <td style="padding:8px;border:1px solid #e5e7eb;color:${color};font-weight:bold">${issue.status}</td>
    <td style="padding:8px;border:1px solid #e5e7eb;font-size:11px;word-break:break-all">${issue.url}${fields}</td>
    <td style="padding:8px;border:1px solid #e5e7eb;font-size:12px">${issue.note}</td>
    <td style="padding:8px;border:1px solid #e5e7eb;font-size:12px">${action}</td>
  </tr>`;
}

const html = `<html><body style="font-family:Arial,sans-serif;color:#111827;max-width:950px;margin:0 auto">
<h2 style="color:#dc2626">⚠ TermsIQ URL Agent — Action Required</h2>
<p><strong>${issues.length} issue(s)</strong> on ${data.runDate} | Checked: ${data.totalChecked} | OK: ${data.totalOk} | Blocked (403): ${data.totalBlocked} | Skipped: ${data.totalSkipped}</p>
<table style="border-collapse:collapse;width:100%;font-size:13px">
<thead><tr style="background:#f3f4f6">
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Record</th>
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Status</th>
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">URL</th>
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Note</th>
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Action</th>
</tr></thead>
<tbody>${rows}</tbody>
</table>
<h3>Next steps</h3>
<ol>
  <li>Update the URL in <code>annotation_base.json</code></li>
  <li>Update the URL in the <strong>Build URL List</strong> node in this workflow</li>
  <li>Re-run <code>python poc/Annotations/url_agent.py</code> to confirm the fix</li>
</ol>
<p style="color:#6b7280;font-size:12px">— TermsIQ URL Agent | ${data.runTimestamp}</p>
</body></html>`;

return [{ json: { ...data, emailHtml: html,
  emailSubject: `⚠ TermsIQ URL Agent — ${issues.length} issue(s) — ${data.runDate}` } }];

const d = $input.first().json;
console.log(`[TermsIQ URL Agent] ${d.runDate} — All OK. Checked: ${d.totalChecked} | OK: ${d.totalOk} | Blocked: ${d.totalBlocked} | Skipped: ${d.totalSkipped}`);
return [{ json: { status: 'ALL_OK', ...d } }];
